@app.route('/enable-mfa', methods=['POST'])
@login_required
@mfa_verified_required
def enable_mfa():
    user_id = session['user_id']
    user = users_db[user_id]

    if user['mfa_enabled']:
        return jsonify({'error': 'MFA is already enabled'}), 400

    # Generate MFA secret
    mfa_secret = pyotp.random_base32()
    user['mfa_secret'] = mfa_secret
    user['updated_at'] = datetime.utcnow().isoformat()

    # Generate provisioning URI for QR code
    totp = pyotp.TOTP(mfa_secret)
    provisioning_uri = totp.provisioning_uri(
        name=user['email'],
        issuer_name='MFA Management System'
    )

    # Generate QR code as base64
    qr = qrcode.QRCode(version=1, box_size=10, border=5)
    qr.add_data(provisioning_uri)
    qr.make(fit=True)
    img = qr.make_image(fill_color='black', back_color='white')
    buffer = io.BytesIO()
    img.save(buffer, format='PNG')
    qr_base64 = base64.b64encode(buffer.getvalue()).decode('utf-8')

    # Generate backup codes
    backup_codes = [secrets.token_hex(4).upper() for _ in range(10)]
    user['mfa_backup_codes'] = backup_codes

    return jsonify({
        'message': 'MFA setup initiated. Please verify with a TOTP code to complete setup.',
        'mfa_secret': mfa_secret,
        'provisioning_uri': provisioning_uri,
        'qr_code_base64': qr_base64,
        'backup_codes': backup_codes,
        'instructions': 'Scan the QR code with your authenticator app, then call /confirm-enable-mfa with a TOTP code.'
    }), 200


@app.route('/confirm-enable-mfa', methods=['POST'])
@login_required
@mfa_verified_required
def confirm_enable_mfa():
    user_id = session['user_id']
    user = users_db[user_id]

    if user['mfa_enabled']:
        return jsonify({'error': 'MFA is already enabled'}), 400

    if not user.get('mfa_secret'):
        return jsonify({'error': 'Please initiate MFA setup first via /enable-mfa'}), 400

    data = request.get_json()
    if not data:
        return jsonify({'error': 'Request body is required'}), 400

    totp_code = data.get('totp_code', '').strip()
    if not totp_code:
        return jsonify({'error': 'TOTP code is required to confirm MFA setup'}), 400

    totp = pyotp.TOTP(user['mfa_secret'])
    if totp.verify(totp_code, valid_window=1):
        user['mfa_enabled'] = True
        user['updated_at'] = datetime.utcnow().isoformat()
        return jsonify({
            'message': 'MFA has been successfully enabled',
            'backup_codes_count': len(user['mfa_backup_codes'])
        }), 200
    else:
        return jsonify({'error': 'Invalid TOTP code. Please try again.'}), 400


@app.route('/disable-mfa', methods=['POST'])
@login_required
@mfa_verified_required
def disable_mfa():
    user_id = session['user_id']
    user = users_db[user_id]

    if not user['mfa_enabled']:
        return jsonify({'error': 'MFA is not enabled'}), 400

    data = request.get_json()
    if not data:
        return jsonify({'error': 'Request body is required'}), 400

    password = data.get('password', '')
    if not check_password_hash(user['password_hash'], password):
        return jsonify({'error': 'Invalid password'}), 401

    user['mfa_enabled'] = False
    user['mfa_secret'] = None
    user['mfa_backup_codes'] = []
    user['updated_at'] = datetime.utcnow().isoformat()

    return jsonify({
        'message': 'MFA has been successfully disabled'
    }), 200


@app.route('/reset-mfa', methods=['POST'])
def reset_mfa():
    """
    Account recovery endpoint: accepts email and sends a reset link.
    The reset link will disable MFA and allow login with just password.
    Verifies email ownership by sending the link to the registered email.
    """
    data = request.get_json()
    if not data:
        return jsonify({'error': 'Request body is required'}), 400

    email = data.get('email', '').strip().lower()
    if not email:
        return jsonify({'error': 'Email is required'}), 400

    # Find user by email
    target_user = None
    for uid, user in users_db.items():
        if user['email'] == email:
            target_user = user
            break

    # Always return success to prevent email enumeration
    success_message = (
        'If an account with that email exists and has MFA enabled, '
        'a reset link has been sent to that email address.'
    )

    if not target_user:
        return jsonify({'message': success_message}), 200

    if not target_user['mfa_enabled']:
        return jsonify({'message': success_message}), 200

    # Generate a secure reset token
    reset_token = secrets.token_urlsafe(48)
    token_expiry = datetime.utcnow() + timedelta(hours=1)

    # Store the reset token
    mfa_reset_tokens[reset_token] = {
        'user_id': target_user['id'],
        'email': email,
        'created_at': datetime.utcnow().isoformat(),
        'expires_at': token_expiry.isoformat(),
        'used': False
    }

    # Build reset link
    reset_link = url_for('confirm_reset_mfa', token=reset_token, _external=True)

    # Send email with reset link
    email_subject = 'MFA Reset Request - Account Recovery'
    email_body = (
        f"Hello {target_user.get('name', 'User')},\n\n"
        f"We received a request to reset the Multi-Factor Authentication (MFA) on your account.\n\n"
        f"Click the following link to disable MFA and regain access to your account:\n\n"
        f"{reset_link}\n\n"
        f"This link will expire in 1 hour.\n\n"
        f"If you did not request this reset, please ignore this email and ensure your account is secure.\n\n"
        f"For security, after using this link:\n"
        f"- MFA will be disabled on your account\n"
        f"- You will be able to log in with just your password\n"
        f"- We strongly recommend re-enabling MFA after logging in\n\n"
        f"Best regards,\n"
        f"MFA Management System Security Team"
    )

    send_email(email, email_subject, email_body)

    return jsonify({'message': success_message}), 200


@app.route('/confirm-reset-mfa', methods=['GET', 'POST'])
def confirm_reset_mfa():
    """
    Endpoint that processes the MFA reset link.
    GET: Shows confirmation page info.
    POST: Confirms the reset and disables MFA.
    """
    token = request.args.get('token') or (request.get_json() or {}).get('token')

    if not token:
        return jsonify({'error': 'Reset token is required'}), 400

    token_data = mfa_reset_tokens.get(token)

    if not token_data:
        return jsonify({'error': 'Invalid or expired reset token'}), 400

    if token_data['used']:
        return jsonify({'error': 'This reset token has already been used'}), 400

    # Check expiry
    expiry = datetime.fromisoformat(token_data['expires_at'])
    if datetime.utcnow() > expiry:
        return jsonify({'error': 'This reset token has expired. Please request a new one.'}), 400

    user_id = token_data['user_id']
    user = users_db.get(user_id)

    if not user:
        return jsonify({'error': 'User account not found'}), 404

    if request.method == 'GET':
        return jsonify({
            'message': 'MFA reset token is valid',
            'email': token_data['email'],
            'instructions': 'Send a POST request to this endpoint with the token to confirm MFA reset.',
            'token': token
        }), 200

    # POST: Perform the MFA reset
    # Mark token as used
    token_data['used'] = True
    token_data['used_at'] = datetime.utcnow().isoformat()

    # Disable MFA
    user['mfa_enabled'] = False
    user['mfa_secret'] = None
    user['mfa_backup_codes'] = []
    user['updated_at'] = datetime.utcnow().isoformat()

    # Invalidate all other reset tokens for this user
    for t_key, t_data in mfa_reset_tokens.items():
        if t_data['user_id'] == user_id and t_key != token:
            t_data['used'] = True

    # Send confirmation email
    send_email(
        user['email'],
        'MFA Has Been Reset - Account Recovery Complete',
        f"Hello {user.get('name', 'User')},\n\n"
        f"Your MFA has been successfully disabled as requested.\n\n"
        f"You can now log in using just your email and password.\n\n"
        f"IMPORTANT: We strongly recommend re-enabling MFA on your account "
        f"as soon as possible for enhanced security.\n\n"
        f"If you did not perform this action, please contact support immediately "
        f"and change your password.\n\n"
        f"Best regards,\n"
        f"MFA Management System Security Team"
    )

    return jsonify({
        'message': 'MFA has been successfully reset. You can now log in with just your password.',
        'email': user['email'],
        'recommendation': 'Please re-enable MFA after logging in for enhanced security.'
    }), 200


