# Cleanup expired tokens periodically (simple approach)
@app.before_request
def cleanup_expired_tokens():
    """Remove expired reset tokens on each request (simple cleanup)."""
    now = datetime.utcnow()
    expired_tokens = [
        token for token, data in mfa_reset_tokens.items()
        if datetime.fromisoformat(data['expires_at']) < now
    ]
    for token in expired_tokens:
        del mfa_reset_tokens[token]


